+			wantErr: "cannot contain ':'",
+		},
+		{
+			name:    "dot",
+			args:    []string{"add", "test.project", "--cc=1"},
+			wantErr: "cannot contain",
+		},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			resetFlags()
+			rootCmd.SetArgs(tt.args)
